// Extract Notion iframe URL from CS Insider page
const response = $input.first().json;
const html = response.content || '';

console.log('CS Insider HTML length:', html.length);

// Look for Notion iframe src
const iframeMatch = html.match(/iframe[^>]+src="(https:\/\/[^"]*notion\.site[^"]+)"/i);

if (iframeMatch) {
  let notionUrl = iframeMatch[1];
  // Clean URL encoding
  notionUrl = notionUrl.replace(/&amp;/g, '&');
  console.log('Found Notion URL from iframe:', notionUrl);
  return [{ json: { notionUrl } }];
}

// Fallback: look for any notion.site URL
const notionMatch = html.match(/https:\/\/[^"\s]*notion\.site\/[a-f0-9-]+/i);
if (notionMatch) {
  console.log('Found Notion URL (fallback):', notionMatch[0]);
  return [{ json: { notionUrl: notionMatch[0] } }];
}

throw new Error('Could not find Notion URL on CS Insider page. HTML length: ' + html.length);

// Parse CS Insider Notion job board - v1.7 (URL-based company extraction)
const response = $input.first().json;

let html = response.content || '';
if (!html && typeof response === 'string') html = response;
if (!html) html = JSON.stringify(response);

const jobs = [];
const today = new Date().toISOString().split('T')[0];

console.log('Notion HTML length:', html.length);

// Extract company from URL (most reliable method)
function extractCompanyFromUrl(url) {
  // Greenhouse: job-boards.greenhouse.io/COMPANY/jobs/...
  let m = url.match(/greenhouse\.io\/([a-z0-9-]+)\//i);
  if (m) return formatCompanyName(m[1]);
  // Lever: jobs.lever.co/COMPANY/...
  m = url.match(/lever\.co\/([a-z0-9-]+)\//i);
  if (m) return formatCompanyName(m[1]);
  // Ashby: jobs.ashbyhq.com/COMPANY/...
  m = url.match(/ashbyhq\.com\/([a-z0-9-]+)\//i);
  if (m) return formatCompanyName(m[1]);
  // Workday: COMPANY.wd1.myworkdayjobs.com
  m = url.match(/\/\/([a-z0-9-]+)\.wd\d\.myworkdayjobs/i);
  if (m) return formatCompanyName(m[1]);
  // Generic: try to get domain name
  m = url.match(/\/\/(?:www\.)?(?:jobs\.)?([a-z0-9-]+)\./i);
  if (m && m[1] !== 'job-boards' && m[1] !== 'careers') return formatCompanyName(m[1]);
  return null;
}

function formatCompanyName(slug) {
  // Convert slug to proper company name
  return slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
}

// Apply links - extract all job URLs
const applyMatches = [];
const applyRegex = /href="(https:\/\/[^"]*(?:greenhouse|lever|workday|ashby|jobs\.|careers|apply|hiring)[^"]*)"/gi;
let match;
while ((match = applyRegex.exec(html)) !== null) {
  const url = match[1];
  if (!url.includes('notion.') && !url.includes('google.com') && !applyMatches.includes(url)) {
    applyMatches.push(url);
  }
}

// Title extraction with validation
function isValidTitle(text) {
  if (/^[:\-\•\*]/.test(text)) return false;
  if (/\d+\+?\s*years?/i.test(text)) return false;
  if (/\b(minimum|required|preferred|must have|experience in|proficiency)\b/i.test(text)) return false;
  if (text.length > 80) return false;
  if (!/\b(Manager|Director|Lead|Head|VP|Associate|Specialist|Coordinator|Partner|Executive)\b/i.test(text)) return false;
  return true;
}

const cleanTitles = [];
const titleRegex = />([^<]*(?:Customer Success|CSM|Client Success|Account Manager|Success Manager|Engagement Manager|Implementation|Onboarding)[^<]*)</gi;
while ((match = titleRegex.exec(html)) !== null) {
  const title = match[1].trim();
  if (title.length > 5 && isValidTitle(title) && !cleanTitles.includes(title)) {
    cleanTitles.push(title);
  }
}

console.log('URLs:', applyMatches.length, 'Titles:', cleanTitles.length);

// Job ID helper
function extractJobId(url) {
  const patterns = [/\/jobs?\/([a-f0-9-]+)/i, /\/postings?\/([a-f0-9-]+)/i, /\/([0-9]+)(?:\?|$)/];
  for (const p of patterns) {
    const m = url.match(p);
    if (m) return m[1];
  }
  let hash = 0;
  for (let i = 0; i < url.length; i++) { hash = ((hash << 5) - hash) + url.charCodeAt(i); hash = hash & hash; }
  return 'csi-' + Math.abs(hash).toString(36);
}

// Build jobs - company from URL, title by index fallback
for (let i = 0; i < applyMatches.length; i++) {
  const jobUrl = applyMatches[i];
  const company = extractCompanyFromUrl(jobUrl);
  if (jobUrl && company) {
    jobs.push({
      json: {
        'Job Title': cleanTitles[i] || 'Customer Success Manager',
        'Company': company,
        'Location': 'Remote',
        'Job URL': jobUrl,
        'Source': 'CS Insider',
        'Date Found': today,
        'Job ID': extractJobId(jobUrl)
      }
    });
  }
}

if (jobs.length === 0) {
  console.log('No jobs found - check HTML sample');
  console.log('Sample:', html.substring(0, 1000));
  return [];
}

return jobs;
